<template><div class="panel-section"><h2 class="section-heading">訪談資訊</h2><div v-if="!iv" class="empty-state">請先選取訪談</div><div v-else class="card"><div class="form-row"><div class="form-group"><label class="form-label">日期</label><input type="date" class="form-input" v-model="iv.interview_date"></div><div class="form-group"><label class="form-label">標題</label><input class="form-input" v-model="iv.title"></div></div><div class="form-group"><label class="form-label">訪談 memo</label><textarea class="form-textarea" v-model="iv.note"></textarea></div><button class="btn btn-primary" @click="save">儲存</button></div></div></template><script setup>import{computed}from'vue';import{useAppStore}from'../stores/appStore.js';const store=useAppStore(),iv=computed(()=>store.currentInterview);async function save(){await store.saveInterview(iv.value);store.toast('訪談資訊已儲存')}</script>
